#include <bits/stdc++.h>
using namespace std;
int n,g[102][102],b[102],sum,ans;
void dfs(int x,int y){
    if(sum>=ans)return;
    if(x==y)ans=sum;
    else{
        for(int i=1;i<=n;i++){
            if(!b[i] && g[x][i]){
                sum+=g[x][i],b[i]=1;
                dfs(i,y);
                sum-=g[x][i],b[i]=0;
            }
        }
    }
}
int main(){
    int m;
    cin>>n>>m;
    while(m--){
        int tp;
        cin>>tp;
        if(tp==0){
            int u,v;
            cin>>u>>v;
            b[u]=1,ans=pow(2,30);
            dfs(u,v);
            if(ans<(1<<30))cout<<ans<<endl;
            else cout<<-1<<endl;
            b[u]=0;
        }else{
            int u,v,e;
            cin>>u>>v>>e;
            g[u][v]=g[v][u]=(g[u][v]==0?e:min(g[u][v],e));
        }
    }
    return 0;
}
